head.script:
// 전역변수
scwin.isDate = ""; //작업번호의 마지막 마감완료일
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = scwin.strCurDate.substring(0, 6) + "01";//당월 1일

scwin.sortId = "";
scwin.sortOrder = -1;

scwin.onpageload = function() {

};

/**
 * UDC값
 */
scwin.onUdcCompleted = async function() {
    scwin.isDate = await udc_check.cfLastJobCloseDate("TR39","YM"); //공통함수필요

    ica_FromDate.setValue(scwin.strPreDate);
    ica_ToDate.setValue(scwin.strCurDate);
    await scwin.lfn_firstRowCodeSetting(); //첫번째 row의 거래처번호 setting
    await scwin.lfn_SetGridFormat();
    ica_FromDate.focus();
};

//-------------------------------------------------------------------------
// Set Grid_Format
//-------------------------------------------------------------------------
scwin.lfn_SetGridFormat = async function() {
    // 동적인 컬럼를 표시하기 위해서, 거래하는 정유사 갯수 구하기
    await scwin.lfn_oilComapnyCnt();

    var setCnt = 0;
    for( var i=0 ; i < ds_oilCompanyCnt.getRowCount() ; i++ ) {
        var lgs_code = ds_oilCompanyCnt.getCellData(i, "code");
        var lgs_name = ds_oilCompanyCnt.getCellData(i, "name");

        gr_oilUnitPrice.setHeaderValue("h_oilInUpr" + (i+1), lgs_name);
        setCnt++;
    }

    for (var i = setCnt ; i < 12 ; i++) {
        gr_oilUnitPrice.setColumnVisible("oilInUpr" + (i+1), false);
    }

	document.body.focus();	
};

//-------------------------------------------------------------------------
// 동적인 컬럼를 표시하기 위해서, 거래하는 정유사 갯수 구하기
//-------------------------------------------------------------------------
scwin.lfn_oilComapnyCnt = async function() {
    ds_oilCompanyCnt_saerch.set("cmd", "retriveOilComapnyCnt");
    var rs = await $c.sbm.execute(sbm_oilCompanyCnt);
    if( rs.responseJSON.resultDataSet[0].Msg == "SUCC" ) {
        ds_oilCompanyCnt.setJSON(rs.responseJSON.GAUCE);
    };
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    await scwin.lfn_SetGridFormat();

    //날짜 체크 start---------------------------------------
    let stDt = ica_FromDate.getValue();
    let endDt = ica_ToDate.getValue();

    if (!await $c.gus.cfIsAfterDate(stDt, endDt)) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_039)); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_FromDate.focus();
        return;
    }
    //날짜 체크 end---------------------------------------	
    let arrSort = gr_oilUnitPrice.getSortableStatus();    
    for( var i=0; i < arrSort.length; i++ ) {
        if( arrSort[i].colID == "stdDt" ) {
            console.log("==============arrSort["+i+"]"+arrSort[i].colID+", sortOrder:"+arrSort[i].sortOrder);
            scwin.sortId = arrSort[i].colID;
            scwin.sortOrder = arrSort[i].sortOrder;
            // ds_oilUnitPrice.sort("stdDt", arrSort[i].sortOrder);
        }
    }

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    ds_saveOilUnitPrice.removeAll();
    ds_firstRowCodeSetting.removeAll();

    scwin.lfn_firstRowCodeSetting(); //첫번째 row의 거래처번호 setting

    totalRows.setValue(ds_oilUnitPrice.getRowCount());

    if( ds_oilUnitPrice.getRowCount() == 0 ) {
        await $c.win.alert(MSG_CM_WRN_002);
    } else {
        // ds_oilUnitPrice.sort("stdDt", 0);
        if( scwin.sortId != "" ) {
             console.log("==============scwin.sortId:"+scwin.sortId+", scwin.sortOrder:"+scwin.sortOrder);
             let order = 2;
            if( scwin.sortOrder == -1 ) {
                order = 1;
            } else if(  scwin.sortOrder == 1 ) {
                order = 0;
            }
            ds_oilUnitPrice.sort("stdDt", order);
        }
        scwin.sortId = "";
        scwin.sortOrder = 0;
    }
};

//-------------------------------------------------------------------------
// 첫번째 row 거래처번호 setting하기
//-------------------------------------------------------------------------
scwin.lfn_firstRowCodeSetting = async function() {
    if(ds_oilUnitPrice.getRowCount() == 0) {
		var rowIndex = ds_firstRowCodeSetting.insertRow();

		await scwin.lfn_oilComapnyCnt();
		if( ds_oilCompanyCnt.getRowCount() > 0 ) {
			for( let i=0; i < ds_oilCompanyCnt.getRowCount(); i++) {
			    let lgs_code = ds_oilCompanyCnt.getCellData(i, "code");
                let vClntNo = "clntNo" + (i+1);
			    ds_firstRowCodeSetting.setCellData(rowIndex, vClntNo.toString(), lgs_code);
			}
		}	
	}else {
		//row갯수 만큼,, 루프돌리기
		for(let j=0; j < ds_oilUnitPrice.getRowCount() ; j++) {
			var rowIndex = ds_firstRowCodeSetting.insertRow();

			await scwin.lfn_oilComapnyCnt();
			if(ds_oilCompanyCnt.getRowCount() > 0 ) {
				for( let i=0; i < ds_oilCompanyCnt.getRowCount(); i++) {
				    let lgs_code = ds_oilCompanyCnt.getCellData(i, "code");
                    let vClntNo = "clntNo" + (i+1);        
				    ds_firstRowCodeSetting.setCellData(j, vClntNo.toString(), lgs_code);
				}
			}
		}
	}	
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if(ds_oilUnitPrice.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ['유류단가 그리드'] );	//변경된 정보가 없습니다.
        return;
	}
    if( !await $c.gus.cfValidate(gr_oilUnitPrice, null, true) ) return;


	await scwin.lfn_checkValue();

	if( scwin.isDate != null ) {
	    //당월 체크    
		if( !await scwin.f_chkMonth() ) {
			ds_saveOilUnitPrice.removeAll();
			return;	
		}
	}

	if( ds_saveOilUnitPrice.getRowCount() == 0 ) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_041, [ '[입력된 유류단가가 없는 경우]','저장']);  //"@은(는) @할 수 없습니다.";
		return;
	}

	if(await $c.win.confirm(MSG_CM_CRM_001) == true){ //저장하시겠습니까?
        $c.sbm.execute(sbm_saveOilPrice);
	} else {
        scwin.f_Retrieve();
        ds_saveOilUnitPrice.removeAll();
    }
};

scwin.sbm_saveOilPrice_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
        ds_saveOilUnitPrice.removeAll();
   }
};

//-------------------------------------------------------------------------
// 당월 체크
//-------------------------------------------------------------------------
scwin.f_chkMonth = async function() {
    let chkRowStatus = "";
    let yyyymmdd = "";
    let yyyymm = "";

    //row갯수 만큼,, 루프돌리기
    for (let j = 0; j < ds_saveOilUnitPrice.getRowCount(); j++) {
        chkRowStatus = ds_saveOilUnitPrice.getRowStatus(j);
        yyyymmdd = ds_saveOilUnitPrice.getCellData(j, 'stdDt');
        yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);

        if( chkRowStatus=="C" || chkRowStatus=="D" || chkRowStatus=="U" ){
            if (yyyymm > yyyymmdd.substring(0, 6)) {
                await $c.win.alert($c.data.getMessage(MSG_CM_ERR_041, ['기준일자의 해당 월에 대한 마감여부가 [마감중]또는 [마감완료]인 경우'],'저장')); //"@은(는) @할 수 없습니다.";
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
//  값 담을 그리드만들기
//-------------------------------------------------------------------------
scwin.lfn_checkValue = async function() {
    ds_saveOilUnitPrice.removeAll();
    let cntUpdateRow = ds_oilUnitPrice.getRowCount();

    // row갯수 만큼,, 루프돌리기
    for( let j=0; j < cntUpdateRow; j++ ) {
        let checkedOrgRowStatus = ds_oilUnitPrice.getRowStatus(j); // C, U, D, R

        // Insert
        if (checkedOrgRowStatus == "C") { 
            await scwin.lfn_oilComapnyCnt(); 
            if (ds_oilCompanyCnt.getRowCount() > 0 ) {

                //column갯수 만큼,, 루프돌리기 
                for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) { 
                    if( i==0 ) {
                        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                        let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");

                        if (org_oilInUpr != null && org_oilInUpr != 0) {
                            let newRow = ds_saveOilUnitPrice.insertRow();

                            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
                            ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
                        }    

                    } else {

                        let org_oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);

                        if (org_oilInUpr2 != null && org_oilInUpr2 != 0) {
                            let newRow = ds_saveOilUnitPrice.insertRow();

                            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
                            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr2);
                            ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
                        }
                    }
                }// for-end 
            } else {
                let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");

                if (org_oilInUpr != null && org_oilInUpr != 0) {
                    let newRow = ds_saveOilUnitPrice.insertRow();

                    ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                    ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                    ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
                    ds_saveOilUnitPrice.modifyRowStatus(newRow, "C");
                }
            }
        } else if (checkedOrgRowStatus == "D") {
            await scwin.lfn_oilComapnyCnt();

            if (ds_oilCompanyCnt.getRowCount() > 0 ) {

                //column갯수 만큼,, 루프돌리기 
                for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
                    if(i==0) {
                        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                        let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
                        let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");

                        let newRow = ds_saveOilUnitPrice.insertRow();
                        //기준일자,순번,거래처번호,유류입고단가
                        ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                        ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
                        ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                        ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
                        ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete

                    } else {

                        let org_oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);

                        let newRow = ds_saveOilUnitPrice.insertRow();
                        //기준일자,순번,거래처번호,유류입고단가
                        ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt")); 
                        ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", ds_oilUnitPrice.getCellData(j, "inUprSeq"+ i));
                        ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
                        ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr2);
                        ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
                    }
                }
            } else {
                let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
                let org_oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");

                let newRow = ds_saveOilUnitPrice.insertRow();
                //기준일자,순번,거래처번호,유류입고단가	
                ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
                ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", org_oilInUpr);
                ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
            }
        } else if (checkedOrgRowStatus == "U") {
            await scwin.lfn_oilComapnyCnt();

            if (ds_oilCompanyCnt.getRowCount() > 0 ) {

                //column갯수 만큼,, 루프돌리기 
                for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) {

                    if(i==0) {
                        let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                        let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
                        let oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
                        let orgOilInUpr = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr");

                        if (orgOilInUpr != oilInUpr) {
                            let newRow = ds_saveOilUnitPrice.insertRow();
                            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                            ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
                            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr);

                            if (orgOilInUpr == 0 || orgOilInUpr == null) {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
                            } else {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "U"); // Update
                            }
                            if (oilInUpr == 0 || oilInUpr == null) {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
                            }
                        }
                    } else {
                        let oilInUpr2 = ds_oilUnitPrice.getCellData(j, "oilInUpr" + i);
                        let orgOilInUpr2 = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr" + i);

                        if (orgOilInUpr2 != oilInUpr2) {
                            let newRow = ds_saveOilUnitPrice.insertRow();
                            ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                            ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", ds_oilUnitPrice.getCellData(j, "inUprSeq"+ i));
                            ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", ds_oilUnitPrice.getCellData(j, "clntNo" + i));
                            ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr2);

                            if (orgOilInUpr2 == 0 || orgOilInUpr2 == null) {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "C");
                            } else {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "U");
                            }
                            if (oilInUpr2 == 0 || oilInUpr2 == null) {
                                ds_saveOilUnitPrice.modifyRowStatus(newRow, "D");
                            }
                        }
                    }
                }
            } else {
                let org_clntNo = ds_oilUnitPrice.getCellData(j, "clntNo");
                let org_inUprSeq = ds_oilUnitPrice.getCellData(j, "inUprSeq");
                let oilInUpr = ds_oilUnitPrice.getCellData(j, "oilInUpr");
                let orgOilInUpr = ds_oilUnitPrice.getOriginalCellData(j, "oilInUpr");

                if (orgOilInUpr != oilInUpr) {
                    let newRow = ds_saveOilUnitPrice.insertRow();
                    ds_saveOilUnitPrice.setCellData(newRow, "stdDt", ds_oilUnitPrice.getCellData(j, "stdDt"));
                    ds_saveOilUnitPrice.setCellData(newRow, "inUprSeq", org_inUprSeq);
                    ds_saveOilUnitPrice.setCellData(newRow, "oilCoClntNo", org_clntNo);
                    ds_saveOilUnitPrice.setCellData(newRow, "oilInUpr", oilInUpr);

                    if (orgOilInUpr == 0 || orgOilInUpr == null) {
                        ds_saveOilUnitPrice.modifyRowStatus(newRow, "C"); // Insert
                    } else {
                        ds_saveOilUnitPrice.modifyRowStatus(newRow, "U"); // Update
                    }
                    if (oilInUpr == 0 || oilInUpr == null) {
                        ds_saveOilUnitPrice.modifyRowStatus(newRow, "D"); // Delete
                    }
                }
            }
        }        
    }//for-end
};

//-------------------------------------------------------------------------
// 그리드에서, 칼럼이 PK일 경우 : update 막기, insert는 입력가능하도록 하는 함수
//------------------------------------------------------------------------- 
scwin.f_EditNone = function() {
    gr_oilUnitPrice.setColumnReadOnly("stdDt", true);
};
scwin.f_EditTrue = function() {
    gr_oilUnitPrice.setColumnReadOnly("stdDt", false);
    scwin.f_EditTrueOilInUpr();
};
scwin.f_EditControl = function(Row, Colid) {
    /*=====  insert[1],delete[2],update[3]  =====*/
    if (Row >= 0) {
        if (ds_oilUnitPrice.getRowStatus(Row) == "C") {
            scwin.f_EditTrue();
        } else {
            scwin.f_EditNone();
            if (scwin.isDate != null) {
                scwin.f_chkEdit();
            }
        }
    }
};

scwin.f_chkEdit = function(row) {
    let yyyymmdd = ds_oilUnitPrice.getCellData(ds_oilUnitPrice.getRowPosition(), 'stdDt');
    let yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);

    if (yyyymm > yyyymmdd.substring(0, 6)) {
        scwin.f_EditNoneOilInUpr();
    } else {
        scwin.f_EditTrueOilInUpr();
    }
};
scwin.f_EditNoneOilInUpr = async function() {
    await scwin.lfn_oilComapnyCnt();
    if (ds_oilCompanyCnt.getRowCount() >= 1) {
        for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
            let vOilInUpr = "oilInUpr"+i;
            gr_oilUnitPrice.setColumnReadOnly(vOilInUpr.toString(), true);
        }
    }
};
scwin.f_EditTrueOilInUpr = async function() {
    await scwin.lfn_oilComapnyCnt();
    if (ds_oilCompanyCnt.getRowCount() >= 1) {
        for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
            let vOilInUpr = "oilInUpr"+i;
            gr_oilUnitPrice.setColumnReadOnly(vOilInUpr.toString(), false);
        }
    }
};

//-------------------------------------------------------------------------
// 그리드 : 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = async function() {
    let row = ds_oilUnitPrice.insertRow();
    // ds_oilUnitPrice.setCellData(row, "oilInUpr0", 0);
    if (scwin.isDate != null) {
        let yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);
        ds_oilUnitPrice.setCellData(row, 'stdDt', yyyymm);
    }

    await scwin.lfn_oilComapnyCnt();
    if (ds_oilCompanyCnt.getRowCount() > 0 ) {
        for (let i=0; i <= ds_oilCompanyCnt.getRowCount(); i++) {
            let vClntNo = "clntNo"+i;
            let org_clntNo = ds_firstRowCodeSetting.getCellData(0, vClntNo.toString());            
            ds_oilUnitPrice.setCellData(row, vClntNo.toString(), org_clntNo);
        }
    }
    gr_oilUnitPrice.setFocusedCell(row,'stdDt');
};

//-------------------------------------------------------------------------
// 그리드 : 행삭제 
//-------------------------------------------------------------------------
scwin.f_DelRow = async function() {
    let row = ds_oilUnitPrice.getRowPosition();
    if (scwin.isDate != null) {
        let yyyymmdd = ds_oilUnitPrice.getCellData(row, 'stdDt');
        let yyyymm = scwin.lfn_GetMonth(scwin.isDate, 1, 1);

        if (yyyymm > yyyymmdd.substring(0, 6)) {
            await $c.win.alert($c.data.getMessage(MSG_CM_ERR_041, ['기준일자의 해당 월에 대한 마감여부가 [마감중]또는 [마감완료]인 경우'],'삭제'));
            return;
        } else if(ds_oilUnitPrice.getRowStatus(row)=="C") {
            ds_oilUnitPrice.removeRow(row);
        } else{
            ds_oilUnitPrice.deleteRow(row);
        }
    } else {
        ds_oilUnitPrice.deleteRow(row);
    }
    gr_oilUnitPrice.setFocusedCell(row,'stdDt');
};

//------------------------------------------------------------------------- 
// 해당월에서 iBase만큼 차이가 나는 월을 구한다.
//------------------------------------------------------------------------- 
scwin.lfn_GetMonth = function(sYearMonth, iBase, iMod) {
    let sYear = parseFloat(sYearMonth.substring(0, 4));
    let sMonth = parseFloat(sYearMonth.substring(4, 6));
    let sResult;

    sMonth = sMonth + iBase;

    if (sMonth >= 13) {
        sMonth = sMonth - 12;
        sYear = sYear + 1;
    } else if (sMonth <= 0) {
        sMonth = sMonth + 12;
        sYear = sYear - 1;
    }

    if (sMonth < 10)
        sResult = sYear.toString() + '0' + sMonth.toString();
    else
        sResult = sYear.toString() + sMonth.toString();

    return sResult;
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
    let gridColCount = 0;
    for(let i = 0; i < gr_oilUnitPrice.getTotalCol(); i++){
        if(gr_oilUnitPrice.getColumnVisible(i)==true){
            gridColCount++;
        }
    }
    let count = ds_oilUnitPrice.getRowCount();
    if (!(count > 0)) return;

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "유류단가",
        textAlign : "center",     //정렬
        fontSize : 12,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 2,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "기준일자 ["+$c.gus.cfGetFormatStr(ica_FromDate.getValue(), "####/##/##")+" ~ "+$c.gus.cfGetFormatStr(ica_ToDate.getValue(), "####/##/##")+"]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    }]

    const options = {
        fileName: "유류단가.xlsx",
        sheetName: "유류단가",
        startRowIndex : 3,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_oilUnitPrice, options,infoArr);
};

//-------------------------------------------------------------------------
// 엑셀업로드
//-------------------------------------------------------------------------
scwin.f_ExcelUp = async function() {
    if( udc_topGrd.getUpExt() == "1" ) {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "header":"1",
            "type": "1",
            "startRowIndex":0,    // 시작row
            "skipSpace":"1",       // 공백무시 여부(1이면 무시 0이면 포함)
            "hidden":"0",           // 왼쪽히든값유무(미포함)
            "fillHidden":"0"        // 오른쪽히든값유무(무시)
        };
        ds_fileUp.removeAll();
        await $c.data.uploadGridViewCSV(gr_fileUp, options); // CSV 파일 업로드
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "type": "1",
            "headerExist":"1",
            "startRowIndex":0,  // 시작row
            "skipSpace":"1",       // 공백무시 여부(1이면 무시 0이면 포함)
            "footerExist":"0"
        };
        ds_fileUp.removeAll();
        await $c.data.uploadGridViewExcel(gr_fileUp, options);
    }
};

//-------------------------------------------------------------------------
// 업로드 완료 이벤트
//-------------------------------------------------------------------------
scwin.gr_fileUp_onfilereadend = async function (value) {
    if( ds_fileUp.getRowCount() == 0 ) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if( await scwin.f_AddRowUploaded() ) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert("업로드작업이 완료되었습니다.");
    }
};

